import{_ as s,o as n,c as e,aA as i}from"./chunks/framework.CgEoSciN.js";const u=JSON.parse('{"title":"Downloading and Reading NASA Precipitation Datasets","description":"","frontmatter":{},"headers":[],"relativePath":"using/download.md","filePath":"using/download.md","lastUpdated":null}'),t={name:"using/download.md"};function o(p,a,l,d,c,r){return n(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="Downloading-and-Reading-NASA-Precipitation-Datasets" tabindex="-1">Downloading and Reading NASA Precipitation Datasets <a class="header-anchor" href="#Downloading-and-Reading-NASA-Precipitation-Datasets" aria-label="Permalink to &quot;Downloading and Reading NASA Precipitation Datasets {#Downloading-and-Reading-NASA-Precipitation-Datasets}&quot;">​</a></h1><p>In this page we show how you can download data for a given <code>NASAMergedTb</code> dataset.</p><h3 id="Setup" tabindex="-1">Setup <a class="header-anchor" href="#Setup" aria-label="Permalink to &quot;Setup {#Setup}&quot;">​</a></h3><div class="language-@example vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">@example</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>using NASAPrecipitation</span></span>
<span class="line"><span>using CairoMakie</span></span>
<span class="line"><span>using DelimitedFiles</span></span>
<span class="line"><span></span></span>
<span class="line"><span>download(&quot;https://raw.githubusercontent.com/natgeo-wong/GeoPlottingData/main/coastline_resl.txt&quot;,&quot;coast.cst&quot;)</span></span>
<span class="line"><span>coast = readdlm(&quot;coast.cst&quot;,comments=true)</span></span>
<span class="line"><span>clon  = coast[:,1]</span></span>
<span class="line"><span>clat  = coast[:,2]</span></span>
<span class="line"><span>nothing</span></span></code></pre></div><h2 id="Required-dependencies" tabindex="-1">Required dependencies <a class="header-anchor" href="#Required-dependencies" aria-label="Permalink to &quot;Required dependencies {#Required-dependencies}&quot;">​</a></h2><p>Since we are downloading from NASA&#39;s EOSDIS OPeNDAP servers, you are required to perform the following:</p><ol><li><p>You need to register an account with Earthdata and allow access to the NASA EOSDISC on it.</p></li><li><p>Create a <code>.netrc</code> file with the following information: <code>machine urs.earthdata.nasa.gov login &lt;your login&gt; password &lt;your password&gt;</code></p></li><li><p>Create a <code>.dodsrc</code> file with the following lines: (1) <code>HTTP.COOKIEJAR=/&lt;home directory&gt;/.urs_cookies</code> and (2) <code>HTTP.NETRC=/&lt;home directory&gt;/.netrc</code></p></li></ol><p>If this sounds complicated however, fear not! You need only perform the first step yourself (i.e. create your own account), for NASAPrecipitation.jl will automatically set up the <code>.dodsrc</code> file (if you don&#39;t already have one), and once you have your <code>&lt;login&gt;</code> and <code>&lt;password&gt;</code>, you can use the function <code>setup()</code> to set up your <code>.netrc</code> file.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setup(</span></span>
<span class="line"><span>    login = &lt;username&gt;</span></span>
<span class="line"><span>    password = &lt;password&gt;</span></span>
<span class="line"><span>)</span></span></code></pre></div><h2 id="Downloading-NASAPrecipitationDatasets" tabindex="-1">Downloading <code>NASAPrecipitationDataset</code>s <a class="header-anchor" href="#Downloading-NASAPrecipitationDatasets" aria-label="Permalink to &quot;Downloading \`NASAPrecipitationDataset\`s {#Downloading-NASAPrecipitationDatasets}&quot;">​</a></h2><p>Downloading NASA Precipitation data is as simple as</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">npd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> NASAPrecipitationDataset</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(args</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">geo </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> GeoRegion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(args</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">download</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(npd,geo)</span></span></code></pre></div><p>Let us download the <code>IMERGMonthly</code> Dataset for 2020 over the Caribbean (as defined by the AR6 IPCC), for example</p><div class="language-@example vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">@example</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npd = IMERGMonthly(start=Date(2020),stop=Date(2020))</span></span>
<span class="line"><span>geo = GeoRegion(&quot;AR6_CAR&quot;)</span></span>
<span class="line"><span>lsd = getLandSea(npd,geo)</span></span>
<span class="line"><span>download(npd,geo)</span></span></code></pre></div><h2 id="Reading-data-for-a-downloaded-NASAPrecipitationDataset" tabindex="-1">Reading data for a downloaded <code>NASAPrecipitationDataset</code> <a class="header-anchor" href="#Reading-data-for-a-downloaded-NASAPrecipitationDataset" aria-label="Permalink to &quot;Reading data for a downloaded \`NASAPrecipitationDataset\` {#Reading-data-for-a-downloaded-NASAPrecipitationDataset}&quot;">​</a></h2><p>And now that you have downloaded the data, you can use the function <code>read()</code> to call the <code>NCDataset</code> that points towards the downloaded data.</p><div class="language-@example vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">@example</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ds = read(npd,geo,Date(2020))</span></span></code></pre></div><p>As shown in the printout of the <code>NCDataset</code>, the precipitation data is saved under the field name <code>precipitation</code>, and is in units of <code>kg m**-2 s**-1</code>, or alternatively <code>mm s**-1</code>.</p><div class="language-@example vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">@example</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>prcp = ds[&quot;precipitation&quot;][:,:,:] * 3600</span></span>
<span class="line"><span>close(ds)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fig = Figure()</span></span>
<span class="line"><span>_,_,slon,slat = coordGeoRegion(geo)</span></span>
<span class="line"><span>aspect = (maximum(slon)-minimum(slon))/(maximum(slat)-minimum(slat))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ax = Axis(</span></span>
<span class="line"><span>    fig[1,1],width=350,height=350/aspect,</span></span>
<span class="line"><span>    title=&quot;February 2020&quot;,xlabel=&quot;Longitude / º&quot;,ylabel=&quot;Latitude / º&quot;,</span></span>
<span class="line"><span>    limits=(minimum(slon)-2,maximum(slon)+2,minimum(slat)-2,maximum(slat)+2)</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>contourf!(</span></span>
<span class="line"><span>    ax,lsd.lon,lsd.lat,prcp[:,:,2],colormap=:Blues,</span></span>
<span class="line"><span>    levels=range(0,0.5,length=11),extendlow=:auto,extendhigh=:auto</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>lines!(ax,clon,clat,color=:black)</span></span>
<span class="line"><span>lines!(ax,slon,slat,color=:red,linewidth=5)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ax = Axis(</span></span>
<span class="line"><span>    fig[1,2],width=350,height=350/aspect,</span></span>
<span class="line"><span>    title=&quot;August 2020&quot;,xlabel=&quot;Longitude / º&quot;,</span></span>
<span class="line"><span>    limits=(minimum(slon)-2,maximum(slon)+2,minimum(slat)-2,maximum(slat)+2)</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>contourf!(</span></span>
<span class="line"><span>    ax,lsd.lon,lsd.lat,prcp[:,:,8],colormap=:Blues,</span></span>
<span class="line"><span>    levels=range(0,0.5,length=11),extendlow=:auto,extendhigh=:auto</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>lines!(ax,clon,clat,color=:black)</span></span>
<span class="line"><span>lines!(ax,slon,slat,color=:red,linewidth=5)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>hideydecorations!(ax, ticks = false,grid=false)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>resize_to_layout!(fig)</span></span>
<span class="line"><span>fig</span></span></code></pre></div><h2 id="Where-is-the-data-saved-to?" tabindex="-1">Where is the data saved to? <a class="header-anchor" href="#Where-is-the-data-saved-to?" aria-label="Permalink to &quot;Where is the data saved to? {#Where-is-the-data-saved-to?}&quot;">​</a></h2><p>You can check where the data is saved to for a given dataset, georegion and datetime by using the function <code>npdfnc()</code></p><div class="language-@example vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">@example</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fnc = npdfnc(npd,geo,Date(2020))</span></span></code></pre></div><h2 id="API" tabindex="-1">API <a class="header-anchor" href="#API" aria-label="Permalink to &quot;API {#API}&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Missing docstring.</p><p>Missing docstring for <code>NASAPrecipitation.setup</code>. Check Documenter&#39;s build log for details.</p></div><div class="warning custom-block"><p class="custom-block-title">Missing docstring.</p><p>Missing docstring for <code>NASAPrecipitation.download</code>. Check Documenter&#39;s build log for details.</p></div><div class="warning custom-block"><p class="custom-block-title">Missing docstring.</p><p>Missing docstring for <code>NASAPrecipitation.read</code>. Check Documenter&#39;s build log for details.</p></div><div class="warning custom-block"><p class="custom-block-title">Missing docstring.</p><p>Missing docstring for <code>NASAPrecipitation.npdfnc</code>. Check Documenter&#39;s build log for details.</p></div>`,27)])])}const g=s(t,[["render",o]]);export{u as __pageData,g as default};
